THOUGHT: The crash occurs because loop-vectorize adds a new predecessor (LoopMiddleBlock) to the loop’s unique exit block, but not all PHI nodes in the exit block are updated to include an incoming for that new edge. IV users are fixed and some live-outs handled via VPlan, but unmodeled PHIs remain invalid. I will modify LoopVectorize.cpp to add an undef incoming from LoopMiddleBlock to any exit-block PHIs missing that incoming, right after fixupIVUsers, and then submit the patch.

```bash
python3 - <<'PY'
import io,sys
path = "llvm/lib/Transforms/Vectorize/LoopVectorize.cpp"
with open(path, 'r') as f:
    s = f.read()
needle = "VectorLoop->getHeader(), Plan, State);"
idx = s.find(needle)
if idx == -1:
    print("Needle not found", file=sys.stderr)
    sys.exit(1)
insert_block = r'''

      // Some exit phis may not be modeled in VPlan and thus are not fixed by
      // VPLiveOuts. Ensure structural correctness by adding an incoming edge
      // for the newly inserted predecessor to any remaining phis in the exit
      // blocks that do not yet have one.
      SmallVector<BasicBlock *> ExitBlocksFix;
      OrigLoop->getExitBlocks(ExitBlocksFix);
      for (BasicBlock *ExitBB : ExitBlocksFix) {
        // Skip if there is no new predecessor from the vectorized loop's middle block.
        // Only fix phis when LoopMiddleBlock actually reaches ExitBB.
        bool HasMiddlePred = false;
        for (auto *Pred : predecessors(ExitBB)) {
          if (Pred == LoopMiddleBlock) {
            HasMiddlePred = true;
            break;
          }
        }
        if (!HasMiddlePred)
          continue;
        for (PHINode &PN : ExitBB->phis()) {
          bool HasIncomingFromMiddle = false;
          for (unsigned i = 0, e = PN.getNumIncomingValues(); i != e; ++i) {
            if (PN.getIncomingBlock(i) == LoopMiddleBlock) {
              HasIncomingFromMiddle = true;
              break;
            }
          }
          if (!HasIncomingFromMiddle) {
            PN.addIncoming(UndefValue::get(PN.getType()), LoopMiddleBlock);
          }
        }
      }
'''
new = s[:idx+len(needle)] + insert_block + s[idx+len(needle):]
with open(path, 'w') as f:
    f.write(new)
PY
&& submit-patch
```

